"use strict";(self.webpackChunkfedpat_docs=self.webpackChunkfedpat_docs||[]).push([[4646],{7550:(e,n,o)=>{o.r(n),o.d(n,{assets:()=>l,contentTitle:()=>i,default:()=>p,frontMatter:()=>r,metadata:()=>d,toc:()=>s});var a=o(4848),t=o(8453);const r={id:"word-skill-raw",title:"SKILL.md \u2014 Word Doc",sidebar_label:"SKILL.md"},i="SKILL.md \u2014 Word Doc",d={id:"ia/claude-skills/word-skill-raw",title:"SKILL.md \u2014 Word Doc",description:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente.",source:"@site/docs/ia/claude-skills/word-skill-raw.md",sourceDirName:"ia/claude-skills",slug:"/ia/claude-skills/word-skill-raw",permalink:"/flock-tech-guides/ia/claude-skills/word-skill-raw",draft:!1,unlisted:!1,editUrl:"https://github.com/Mujics/flock-tech-guides/tree/main/flock-tech-guides/docs/ia/claude-skills/word-skill-raw.md",tags:[],version:"current",frontMatter:{id:"word-skill-raw",title:"SKILL.md \u2014 Word Doc",sidebar_label:"SKILL.md"},sidebar:"docs",previous:{title:"Word Skill",permalink:"/flock-tech-guides/ia/claude-skills/word-skill"},next:{title:"Commit Skill",permalink:"/flock-tech-guides/ia/claude-skills/commit-skill"}},l={},s=[];function c(e){const n={a:"a",admonition:"admonition",code:"code",h1:"h1",hr:"hr",p:"p",pre:"pre",...(0,t.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.h1,{id:"skillmd--word-doc",children:"SKILL.md \u2014 Word Doc"}),"\n",(0,a.jsx)(n.p,{children:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente."}),"\n",(0,a.jsx)(n.admonition,{title:"Contribuir",type:"info",children:(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.a,{href:"https://github.com/Flock-engineering/flock-tech-guides/edit/dev/static/skills/word-doc/SKILL.md",children:"\u270f\ufe0f Sugerir correcci\xf3n en GitHub"})," \u2014 GitHub te propone hacer fork y PR autom\xe1ticamente si no ten\xe9s permisos de push."]})}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.a,{href:"pathname:///flock-tech-guides/skills/word-doc/SKILL.md",children:"\u2b07 Descargar SKILL.md"})}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-md",children:'---\nname: word-doc\ndescription: >\n  Genera un documento Word (.docx) con estilo profesional.\n  Trigger: crear documento Word, generar .docx, documento de texto enriquecido\nargument-hint: "[descripci\xf3n del documento]"\nlicense: MIT\nmetadata:\n  author: flock\n  version: \'1.0\'\n  scope: [root]\n  auto_invoke:\n    - \'Crear documento Word\'\n    - \'Generar .docx\'\n    - \'Generar informe Word\'\nallowed-tools: Bash, Read, Write, Glob\ncontext: fork\n---\n\n# Skill: Generar documento Word\n\n## Critical Rules\n\n### ALWAYS\n\n- Verificar si existe `template.docx` antes de crear desde cero\n- Mostrar el outline al usuario y esperar confirmaci\xf3n antes de generar\n- Usar `python3`, nunca `python`\n- Guardar el script temporal siempre en `/tmp/`\n- Incluir portada, header y footer en todos los documentos\n- Eliminar el script temporal despu\xe9s de ejecutarlo\n- Aplicar la gu\xeda de estilos completa (paleta, tipograf\xeda, m\xe1rgenes)\n\n### NEVER\n\n- Continuar al paso 5 sin confirmaci\xf3n expl\xedcita del paso 4\n- Guardar scripts temporales en el directorio del proyecto\n- Omitir portada, header o footer\n- Cambiar la paleta de colores sin que el usuario lo pida\n- Usar `python` en vez de `python3`\n\n---\n\n## 1. Verificar python-docx\n\n```bash\npython3 -c "import docx" 2>/dev/null && echo "OK" || pip3 install python-docx -q\n```\n\n## 2. Buscar template\n\nBusc\xe1 si existe un `template.docx` en el directorio actual o ra\xedz del proyecto:\n\n```bash\nfind . -maxdepth 2 -name "template.docx" 2>/dev/null | head -1\n```\n\n- Si existe \u2192 usalo como base: `Document(\'ruta/template.docx\')` \u2014 hereda estilos, fuentes y encabezados corporativos\n- Si no existe \u2192 cre\xe1 desde cero aplicando la gu\xeda de estilos de este skill\n\n## 3. Entender el documento\n\nAnaliz\xe1 `$ARGUMENTS`:\n\n- Si hay descripci\xf3n suficiente \u2192 continu\xe1\n- Si es vago o vac\xedo \u2192 pregunt\xe1: t\xedtulo, secciones principales, tipo (informe, carta, propuesta, acta, etc.)\n- Si el usuario menciona archivos de datos (CSV, JSON, Excel) \u2192 le\xe9los con Read/Glob **antes** de continuar\n\n## 4. Confirmar estructura antes de generar\n\nMostr\xe1 el outline al usuario y esper\xe1 confirmaci\xf3n expl\xedcita:\n\n```\n\ud83d\udcc4 Voy a generar: nombre_archivo.docx\n\nEstructura:\n  - Portada: [t\xedtulo, subt\xedtulo, autor, fecha]\n  - Secci\xf3n 1: ...\n  - Secci\xf3n 2: ... (tabla con N columnas)\n  - Secci\xf3n 3: ...\n\n\xbfConfirm\xe1s? (s/n)\n```\n\nNo contin\xfaes sin respuesta afirmativa.\n\n## 5. Generar el script Python\n\nEscrib\xed el script en `/tmp/gen_word_doc.py`. Aplic\xe1 **siempre** la gu\xeda de estilos completa:\n\n```python\nimport os\nfrom datetime import date as dt\nfrom docx import Document\nfrom docx.shared import Inches, Pt, RGBColor, Cm\nfrom docx.enum.text import WD_ALIGN_PARAGRAPH\nfrom docx.oxml.ns import qn\nfrom docx.oxml import OxmlElement\n\n# \u2500\u2500 PALETA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nCOLOR_PRIMARY   = RGBColor(0x1F, 0x49, 0x7D)  # azul corporativo\nCOLOR_SECONDARY = RGBColor(0x2E, 0x74, 0xB5)  # azul claro\nCOLOR_TEXT      = RGBColor(0x26, 0x26, 0x26)  # casi negro\nCOLOR_SUBTLE    = RGBColor(0x75, 0x75, 0x75)  # gris\n\n# \u2500\u2500 TIPOGRAF\xcdA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nFONT_BODY    = "Calibri"\nFONT_HEADING = "Calibri"\nSIZE_BODY    = Pt(11)\nSIZE_H1      = Pt(18)\nSIZE_H2      = Pt(14)\nSIZE_H3      = Pt(12)\n\n# \u2500\u2500 M\xc1RGENES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef set_margins(doc, top=2.54, bottom=2.54, left=3.0, right=2.54):\n    for section in doc.sections:\n        section.top_margin    = Cm(top)\n        section.bottom_margin = Cm(bottom)\n        section.left_margin   = Cm(left)\n        section.right_margin  = Cm(right)\n\n# \u2500\u2500 PAGE SIZE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Default: A4 (Argentina, Europa y resto del mundo).\n# US Letter solo para documentos destinados a audiencias norteamericanas.\n#   A4:        Cm(21.0)  x Cm(29.7)   \u2190 default\n#   US Letter: Cm(21.59) x Cm(27.94)\ndef set_page_size(doc, width=Cm(21.0), height=Cm(29.7)):\n    for section in doc.sections:\n        section.page_width  = width\n        section.page_height = height\n\n# \u2500\u2500 HELPERS DE ESTILO \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef style_run(run, size=SIZE_BODY, color=COLOR_TEXT, bold=False, italic=False):\n    run.font.name      = FONT_BODY\n    run.font.size      = size\n    run.font.color.rgb = color\n    run.bold           = bold\n    run.italic         = italic\n\ndef set_cell_bg(cell, hex_color):\n    tc   = cell._tc\n    tcPr = tc.get_or_add_tcPr()\n    shd  = OxmlElement(\'w:shd\')\n    shd.set(qn(\'w:fill\'),  hex_color)\n    shd.set(qn(\'w:color\'), \'auto\')\n    shd.set(qn(\'w:val\'),   \'clear\')\n    tcPr.append(shd)\n\n# \u2500\u2500 P\xc1RRAFO CUERPO \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef add_body_paragraph(doc, text, alignment=WD_ALIGN_PARAGRAPH.JUSTIFY):\n    p   = doc.add_paragraph()\n    run = p.add_run(text)\n    style_run(run)\n    p.alignment                          = alignment\n    p.paragraph_format.space_after       = Pt(6)\n    p.paragraph_format.line_spacing      = Pt(14)\n    return p\n\n# \u2500\u2500 HEADING \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef add_heading(doc, text, level=1):\n    sizes  = {1: SIZE_H1,      2: SIZE_H2,        3: SIZE_H3}\n    colors = {1: COLOR_PRIMARY, 2: COLOR_SECONDARY, 3: COLOR_SECONDARY}\n    p   = doc.add_heading(text, level=level)\n    for run in p.runs:\n        run.font.name      = FONT_HEADING\n        run.font.size      = sizes.get(level, SIZE_H2)\n        run.font.color.rgb = colors.get(level, COLOR_PRIMARY)\n        run.bold           = True\n    p.paragraph_format.space_before = Pt(12)\n    p.paragraph_format.space_after  = Pt(4)\n    return p\n\n# \u2500\u2500 TABLA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# \u26a0\ufe0f  Compatibilidad: siempre usar WidthType.DXA para anchos de columna.\n#     WidthType.PERCENTAGE falla en Google Docs, SharePoint y Word Online.\ndef add_styled_table(doc, headers, rows):\n    table = doc.add_table(rows=1, cols=len(headers))\n    table.style = "Table Grid"\n    # Encabezado\n    hdr_cells = table.rows[0].cells\n    for i, h in enumerate(headers):\n        hdr_cells[i].text = h\n        run = hdr_cells[i].paragraphs[0].runs[0]\n        style_run(run, size=Pt(10), color=RGBColor(0xFF, 0xFF, 0xFF), bold=True)\n        set_cell_bg(hdr_cells[i], \'1F497D\')\n    # Filas con sombreado alternado\n    for idx, row_data in enumerate(rows):\n        row   = table.add_row().cells\n        color = \'DCE6F1\' if idx % 2 == 0 else \'FFFFFF\'\n        for i, val in enumerate(row_data):\n            row[i].text = str(val)\n            run = row[i].paragraphs[0].runs[0]\n            style_run(run, size=Pt(10))\n            set_cell_bg(row[i], color)\n    return table\n\n# \u2500\u2500 HEADER \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef add_header(doc, title, company=""):\n    header = doc.sections[0].header\n    p      = header.paragraphs[0] if header.paragraphs else header.add_paragraph()\n    p.clear()\n    label  = f"{company}  |  {title}" if company else title\n    run    = p.add_run(label)\n    style_run(run, size=Pt(9), color=COLOR_SUBTLE, italic=True)\n    p.alignment = WD_ALIGN_PARAGRAPH.RIGHT\n\n# \u2500\u2500 FOOTER CON N\xdaMERO DE P\xc1GINA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef add_footer_with_page_number(doc):\n    footer = doc.sections[0].footer\n    p      = footer.paragraphs[0] if footer.paragraphs else footer.add_paragraph()\n    p.clear()\n    p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n    run = p.add_run()\n    style_run(run, size=Pt(9), color=COLOR_SUBTLE)\n    for tag, text in [(\'begin\', None), (None, \'PAGE\'), (\'end\', None)]:\n        if tag:\n            el = OxmlElement(\'w:fldChar\')\n            el.set(qn(\'w:fldCharType\'), tag)\n        else:\n            el = OxmlElement(\'w:instrText\')\n            el.text = text\n        run._r.append(el)\n\n# \u2500\u2500 PORTADA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef add_cover_page(doc, title, subtitle="", author="", date=""):\n    doc.add_paragraph()\n    doc.add_paragraph()\n    p = doc.add_paragraph()\n    run = p.add_run(title)\n    style_run(run, size=Pt(28), color=COLOR_PRIMARY, bold=True)\n    p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n    p.paragraph_format.space_after = Pt(8)\n    if subtitle:\n        p = doc.add_paragraph()\n        run = p.add_run(subtitle)\n        style_run(run, size=Pt(16), color=COLOR_SECONDARY)\n        p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n        p.paragraph_format.space_after = Pt(48)\n    doc.add_paragraph()\n    doc.add_paragraph()\n    if author:\n        p = doc.add_paragraph()\n        run = p.add_run(author)\n        style_run(run)\n        p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n    p = doc.add_paragraph()\n    run = p.add_run(date or dt.today().strftime("%d/%m/%Y"))\n    style_run(run, size=Pt(10), color=COLOR_SUBTLE)\n    p.alignment = WD_ALIGN_PARAGRAPH.CENTER\n    doc.add_page_break()\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# DOCUMENTO (adaptar a partir de aqu\xed seg\xfan la solicitud del usuario)\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\ntemplate_path = None  # completar si se encontr\xf3 template.docx\ndoc = Document(template_path) if template_path else Document()\n\nset_page_size(doc)          # A4 por defecto \u2014 US Letter: set_page_size(doc, Cm(21.59), Cm(27.94))\nset_margins(doc)\ndoc.core_properties.author = "Claude"\ndoc.core_properties.title  = "T\xedtulo del documento"\n\nadd_cover_page(doc, title="T\xcdTULO", subtitle="Subt\xedtulo", author="Autor")\nadd_header(doc, title="T\xcdTULO")\nadd_footer_with_page_number(doc)\n\n# --- contenido del documento ---\n\noutput_path = "nombre_del_archivo.docx"\ndoc.save(output_path)\nprint(f"\u2713 {os.path.abspath(output_path)}")\n```\n\n## 6. Ejecutar y limpiar\n\n```bash\npython3 /tmp/gen_word_doc.py && rm /tmp/gen_word_doc.py\n```\n\nVerific\xe1 que el archivo fue creado:\n\n```bash\nls -lh nombre_del_archivo.docx\n```\n\n## 7. Informar al usuario\n\nRespond\xe9 con:\n- Ruta absoluta del archivo generado y su tama\xf1o\n- Resumen de la estructura (secciones, tablas, p\xe1ginas estimadas)\n- Confirmaci\xf3n de que el script temporal fue eliminado\n\n## Professional Document Base\n\nEsqueleto m\xednimo recomendado \u2014 punto de partida copy-paste para cualquier documento:\n\n```python\ndoc = Document()\n\n# Page size: A4 por defecto (Argentina, Europa y resto del mundo)\nset_page_size(doc)\n# US Letter solo para audiencias norteamericanas:\n# set_page_size(doc, width=Cm(21.59), height=Cm(27.94))\n\n# M\xe1rgenes expl\xedcitos\nset_margins(doc, top=2.54, bottom=2.54, left=3.0, right=2.54)\n\n# Header: t\xedtulo + empresa con tab stop alineado a la derecha\nadd_header(doc, title="T\xedtulo del Documento", company="Empresa S.A.")\n\n# Footer: n\xfamero de p\xe1gina centrado\nadd_footer_with_page_number(doc)\n\n# Estilo base de fuente (Arial, 11pt cuerpo)\nFONT_BODY    = "Arial"\nFONT_HEADING = "Arial"\nSIZE_BODY    = Pt(11)\n\n# Portada\nadd_cover_page(doc,\n    title    = "T\xedtulo del Documento",\n    subtitle = "Subt\xedtulo o descripci\xf3n",\n    author   = "Nombre Apellido",\n    date     = "Marzo 2026"\n)\n\ndoc.core_properties.title  = "T\xedtulo del Documento"\ndoc.core_properties.author = "Nombre Apellido"\n\n# --- contenido a partir de aqu\xed ---\n\ndoc.save("documento.docx")\nprint(f"\u2713 {os.path.abspath(\'documento.docx\')}")\n```\n\n## Notas\n\n- Siempre us\xe1 `python3`, nunca `python`\n- El script temporal va **siempre en `/tmp/`**, nunca en el directorio del proyecto\n- Si hay datos externos (CSV, JSON), le\xe9los con Read/Glob **antes** de escribir el script\n- Nunca omitir portada, header o footer\n- La paleta de colores es fija \u2014 solo cambiala si el usuario pide branding propio\n- No contin\xfaes al paso 5 sin confirmaci\xf3n expl\xedcita del paso 4\n- **Page size**: usar A4 (`Cm(21.0) x Cm(29.7)`) por defecto. US Letter (`Cm(21.59) x Cm(27.94)`) solo para documentos destinados a audiencias norteamericanas\n- **Ancho de columnas en tablas**: siempre usar `WidthType.DXA` \u2014 `WidthType.PERCENTAGE` falla en Google Docs, SharePoint y Word Online\n'})})]})}function p(e={}){const{wrapper:n}={...(0,t.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},8453:(e,n,o)=>{o.d(n,{R:()=>i,x:()=>d});var a=o(6540);const t={},r=a.createContext(t);function i(e){const n=a.useContext(r);return a.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function d(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(t):e.components||t:i(e.components),a.createElement(r.Provider,{value:n},e.children)}}}]);